#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int i=1;
        while(i<=N){
            printf("%d", i*i);
            if(i<N) printf(" ");
            i++;
        }
        printf("\n");
    }
    return 0;
}

